form:Form.form:Scripts:
		function PosOnLoad()
{
	if (Ctrl('main').GetMode()=='SHOW')
	{
		var oi_personal_emp = Ctrl('oi_personal_emp').GetXValue();		
		var xmlParam = new NomadXML('PARAM');		
		xmlParam.SetAttr('oi_personal_emp', oi_personal_emp);
		var nSQL = GetProxy().SQLService();		
		var xmlEmpresa = nSQL.GetOBJ(Ctrl('main').getResource('GetEmpresa'), xmlParam.ToString());		
		Ctrl('oi_empresa').SetXValue(xmlEmpresa.oi_empresa);		
		Ctrl('oi_personal_emp').SetXValue(oi_personal_emp);
	}

	if (Ctrl('main').GetMode()=='NEW')
	{
		Ctrl('oi_empresa').SetXValue('');
		Ctrl('chk_forzar').SetXValue('0');
	}
}
